-- =====================================================================
-- get_ai_chat_session_continuity
-- =====================================================================

create or replace function public.get_ai_chat_session_continuity(
  p_project_id uuid,
  p_chat_id uuid
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_ai text;
  v_turns jsonb;
  v_summary text;
  v_max_turns integer := 10;
  v_key uuid;
begin
  if v_uid is null then
    return null;
  end if;

  if not public.can_access_project(p_project_id) then
    return null;
  end if;

  v_ai := public.effective_ai_access_for_profile(p_project_id);
  if v_ai is null or v_ai = 'none' then
    return null;
  end if;

  -- p_chat_id retained in signature for backwards compatibility but
  -- intentionally NOT used in lookup. The canonical session row for
  -- (auth.uid(), p_project_id) is always returned, so a client that mints
  -- a fresh chat_id (e.g. after a page reload) sees the same memory.
  v_key := public.resolve_ai_chat_key(v_uid, p_project_id);

  select s.recent_turns, s.rolling_summary
    into v_turns, v_summary
    from public.project_ai_chat_sessions s
   where s.derived_chat_key = v_key;

  if not found then
    return null;
  end if;

  return jsonb_build_object(
    'recentTurns', public._trim_session_turns_jsonb(v_turns, v_max_turns),
    'rollingSummary', v_summary
  );
end;
$$;

