-- =====================================================================
-- append_ai_chat_session_turns
-- =====================================================================

create or replace function public.append_ai_chat_session_turns(
  p_project_id uuid,
  p_chat_id uuid,
  p_user_text text,
  p_assistant_text text
)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_ai text;
  v_max_msg_len integer := 2000;
  v_max_turns integer := 10;
  v_user text;
  v_asst text;
  v_new_turns jsonb;
  v_canonical_chat_id uuid;
begin
  if v_uid is null then
    return;
  end if;

  if not public.can_access_project(p_project_id) then
    return;
  end if;

  v_ai := public.effective_ai_access_for_profile(p_project_id);
  if v_ai is null or v_ai = 'none' then
    return;
  end if;

  v_user := left(coalesce(p_user_text, ''), v_max_msg_len);
  v_asst := left(coalesce(p_assistant_text, ''), v_max_msg_len);

  v_new_turns := jsonb_build_array(
    jsonb_build_object('role', 'user', 'text', v_user),
    jsonb_build_object('role', 'assistant', 'text', v_asst)
  );

  -- p_chat_id retained in the signature for backwards compatibility but
  -- ignored for identity. The row's chat_id on first INSERT is the
  -- server-derived canonical value, so subsequent calls under different
  -- chat_ids collide on derived_chat_key and append to the same row.
  v_canonical_chat_id := public.resolve_ai_chat_key(v_uid, p_project_id);

  insert into public.project_ai_chat_sessions as s (
    chat_id, project_id, profile_id, recent_turns, rolling_summary, updated_at
  )
  values (
    v_canonical_chat_id,
    p_project_id,
    v_uid,
    public._trim_session_turns_jsonb(v_new_turns, v_max_turns),
    null,
    now()
  )
  on conflict (derived_chat_key) do update
    set recent_turns = public._trim_session_turns_jsonb(
          coalesce(s.recent_turns, '[]'::jsonb) || v_new_turns,
          v_max_turns
        ),
        updated_at = now();
end;
$$;

revoke all on function public.append_ai_chat_session_turns(uuid, uuid, text, text) from public;
grant execute on function public.append_ai_chat_session_turns(uuid, uuid, text, text) to authenticated;

